import warnings; warnings.filterwarnings('ignore')
import numpy as np
from disease_relevant_noninhibited_all_normalized_ode.evaluator import load_all_datasets
from pysr_harness.equation_session import constant_symbols, feature_symbols, evaluate_expression
ds={n:(Xt,Xv,yt,yv) for (n,Xt,Xv,yt,yv) in load_all_datasets()}
targets=['Abeta/Meisl2014/Ab40_sec_IN_HOURS','Abeta/Cohen2013/Ab42_sec_IN_HOURS','htt/Kar2011/Fits/Kar2011_Q37_prim']
def run(name, kind):
    Xt,Xv,yt,yv=ds[name]
    c=constant_symbols(5); x=feature_symbols(3); p,cc=x[1],x[2]
    if kind=='cur':
        e=(c[0]+c[1]*cc)*(1+c[2]*p)*(c[3]-cc); iv=[0.5,1.0,0.0,1.0,0.0]; nc=4; c=constant_symbols(4); x=feature_symbols(3); p,cc=x[1],x[2]; e=(c[0]+c[1]*cc)*(1+c[2]*p)*(c[3]-cc); iv=[0.5,1.0,0.0,1.0]
    else:
        e=(c[0]+c[1]*cc)*(1+c[2]*p)*(c[3]+c[4]*p-cc); iv=[0.5,1.0,0.0,1.0,0.0]
    r=evaluate_expression(e,Xt,yt,Xv,yv,constants=c,initial_values=iv)
    return r.get('nmse_val')
for t in targets:
    print(t, 'cur=%.4f'%run(t,'cur'), 'C=%.4f'%run(t,'C'))
